export const OverlayTooltipWIPStory = (props?: {
  symbolAlignment?: 'left' | 'right';
}) => {
  const { sub, onClick } = usePinAllSetup();

  return (
    <>
      <ToastContainer />
      <Button onClick={onClick}>Pin all</Button>
      <TooltipGrid
        sub={sub}
        items={TooltipData}
        symbolAlignment={props?.symbolAlignment}
      />
    </>
  );
};

